"use client";

/**
 * ConsoleHeader — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "ConsoleHeader" (2934:14478)
 *
 * Barra 991×64 (gradiente morado #5F3ED8→#140046, borde gradiente, sombra).
 * Izquierda: AvatarZone + "Mi C.U.U. ZAEX5G". Derecha: 4 columnas con divisores:
 *   · CONECTADOS  → PriceBadge + número
 *   · OFERTA      → BadgeStatus (live, editable, sin dot)
 *   · FONDOS      → texto
 *   · CONECTIVIDAD→ Signal
 * Compuesta con componentes Concorde.
 */

import type { JSX, ReactNode } from "react";
import AvatarZone from "../../components/AvatarZone/AvatarZone";
import PriceBadge from "../../components/PriceBadge/PriceBadge";
import BadgeStatus from "../../components/BadgeStatus/BadgeStatus";
import Signal from "../../components/Signal/Signal";

export const CONSOLEHEADER_WIDTH = 991;
export const CONSOLEHEADER_HEIGHT = 64;

export interface ConsoleHeaderProps {
  userLabel?: string;
  user?: string;
  conectados?: string;
  oferta?: string;
  fondos?: string;
  conectividad?: number;
  className?: string;
}

function StatCol({ label, children }: { label: string; children: ReactNode }): JSX.Element {
  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 6, padding: "0 18px", minWidth: 0 }}>
      <span style={{ fontSize: 9, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "#ffffff", whiteSpace: "nowrap" }}>{label}</span>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: 22 }}>{children}</div>
    </div>
  );
}

function Divider(): JSX.Element {
  return <div style={{ width: 1, height: 44, background: "rgba(225,227,226,0.32)", flexShrink: 0 }} />;
}

export default function ConsoleHeader({
  userLabel = "Mi C.U.U.",
  user = "ZAEX5G",
  conectados = "18",
  oferta = "47292",
  fondos = "$100",
  conectividad = 4,
  className = "",
}: ConsoleHeaderProps): JSX.Element {
  return (
    <header
      className={className}
      style={{
        boxSizing: "border-box",
        width: CONSOLEHEADER_WIDTH,
        height: CONSOLEHEADER_HEIGHT,
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "0 16px",
        border: "1px solid transparent",
        backgroundImage:
          "linear-gradient(160deg, #5F3ED8 0%, #340091 50%, #140046 100%), linear-gradient(120deg, #ffffff 0%, #F4AC59 22%, #8460E5 74.5%, #ffffff 100%)",
        backgroundOrigin: "border-box",
        backgroundClip: "padding-box, border-box",
        boxShadow: "rgba(0,0,0,0.1) 0px 0px 16px 4px",
        fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
      }}
    >
      {/* Izquierda: avatar + usuario */}
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <AvatarZone size={32} />
        <div style={{ display: "flex", alignItems: "baseline", gap: 6, color: "#ffffff", whiteSpace: "nowrap" }}>
          <span style={{ fontSize: 15, fontWeight: 500 }}>{userLabel}</span>
          <span style={{ fontSize: 16, fontWeight: 800, letterSpacing: "0.01em" }}>{user}</span>
        </div>
      </div>

      {/* Derecha: 4 columnas con divisores */}
      <div style={{ display: "flex", alignItems: "center" }}>
        <StatCol label="Conectados">
          <span style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <PriceBadge size={20} />
            <span style={{ fontSize: 16, fontWeight: 700, color: "#ffffff", fontVariantNumeric: "tabular-nums" }}>{conectados}</span>
          </span>
        </StatCol>
        <Divider />
        <StatCol label="Oferta">
          <BadgeStatus variant="live" label={oferta} icon={false} />
        </StatCol>
        <Divider />
        <StatCol label="Fondos">
          <span style={{ fontSize: 18, fontWeight: 800, color: "#ffffff", fontVariantNumeric: "tabular-nums", letterSpacing: "0.04em" }}>{fondos}</span>
        </StatCol>
        <Divider />
        <StatCol label="Conectividad">
          <Signal level={conectividad} width={30} />
        </StatCol>
      </div>
    </header>
  );
}

/**
 * Sala — Bloque de Concorde (Voyager DS)
 *
 * Sala de subasta. Por ahora es solo el lienzo base: un fondo de 1023 × 1042
 * con el color de marca (#2E0F70). Iremos montando las secciones encima.
 */

import type { JSX } from "react";
import ConsoleHeader from "./ConsoleHeader";
import SalaStatus from "../../components/SalaStatus/SalaStatus";
import CardViewer from "../../components/CardViewer/CardViewer";

export interface SalaProps {
  className?: string;
}

export const SALA_WIDTH = 1023;
export const SALA_HEIGHT = 1042;

const SALA_IMAGES = ["/demo/bronco.jpg", "/demo/bronco.jpg", "/demo/bronco.jpg", "/demo/bronco.jpg"];

export default function Sala({ className = "" }: SalaProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="sala"
      style={{
        position: "relative",
        width: SALA_WIDTH,
        height: SALA_HEIGHT,
        background: "#2E0F70",
        overflow: "hidden",
      }}
    >
      {/* ConsoleHeader 991×64 · a 16px del top, centrado (16px a cada lado) */}
      <div style={{ position: "absolute", top: 16, left: 16 }}>
        <ConsoleHeader />
      </div>

      {/* Banner 204×930 · abajo-izquierda: 16px del left, 16px del bottom, 16px del header */}
      <div
        data-slot="left-banner"
        style={{
          position: "absolute",
          top: 96,
          left: 16,
          width: 204,
          height: 930,
          borderRadius: 8,
          background: "#E9EAEC",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          textAlign: "center",
          fontFamily: "monospace",
          fontSize: 12,
          letterSpacing: "0.08em",
          color: "#9AA1AC",
        }}
      >
        BANNER
        <br />
        204 × 930
      </div>

      {/* SalaStatus + visor · el borde gradiente (slot header de CardViewer) envuelve
          SOLO SalaStatus + el visor; el filmstrip queda aparte, debajo. */}
      <div style={{ position: "absolute", top: 96, left: 236 }}>
        <CardViewer header={<SalaStatus />} images={SALA_IMAGES} />
      </div>
    </div>
  );
}

"use client";

/**
 * AvatarZone — Generado por Concorde
 * Fuente: Figma VOYAGER · "Avatar Zone" (nodo 2035:16583)
 *
 * Avatar circular 32×32: relleno gradiente naranja (#FF9639 → #EF852E → #BE3D00)
 * con silueta de persona blanca centrada. Tamaño personalizable:
 * "sm" (24px) · "md" (32px) · o número de px.
 */

import { useId } from "react";
import type { JSX } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

export type AvatarZoneSize = "sm" | "md";

export interface AvatarZoneProps {
  /** Tamaño: "sm"=24px · "md"=32px · o número de px (default "md") */
  size?: AvatarZoneSize | number;
  /** Texto accesible — si se omite, el avatar es decorativo (aria-hidden) */
  title?: string;
  className?: string;
}

const SIZE_PX: Record<AvatarZoneSize, number> = { sm: 24, md: 32 };

const CIRCLE_PATH =
  "M0 16C0 7.16344 7.16344 0 16 0C24.8366 0 32 7.16344 32 16C32 24.8366 24.8366 32 16 32C7.16344 32 0 24.8366 0 16Z";

// ─── Component ────────────────────────────────────────────────────────────────

export default function AvatarZone({ size = "md", title, className = "" }: AvatarZoneProps): JSX.Element {
  const uid = useId().replace(/:/g, "-");
  const px = typeof size === "number" ? size : SIZE_PX[size];

  return (
    <svg
      width={px}
      height={px}
      viewBox="0 0 32 32"
      fill="none"
      className={className}
      role={title ? "img" : undefined}
      aria-hidden={title ? undefined : true}
      aria-label={title}
    >
      {title ? <title>{title}</title> : null}
      <g clipPath={`url(#${uid}-c0)`}>
        <path d={CIRCLE_PATH} fill={`url(#${uid}-bg)`} />
        <g clipPath={`url(#${uid}-c1)`}>
          <path
            d="M19.5412 11.36C19.5412 9.52 17.9765 8 16 8C14.0235 8 12.5412 9.52 12.5412 11.36C12.5412 13.28 14.0235 14.8 16 14.8C17.9765 14.8 19.5412 13.28 19.5412 11.36ZM9 20.4C10.4824 22.56 13.1176 24 16 24C18.8824 24 21.5176 22.56 23 20.4C23 18.16 18.3059 16.88 16 16.88C13.6941 16.88 9 18.16 9 20.4Z"
            fill="white"
          />
        </g>
      </g>
      <defs>
        <linearGradient id={`${uid}-bg`} x1="5.42742" y1="-16.8777" x2="43.7544" y2="-4.5528" gradientUnits="userSpaceOnUse">
          <stop stopColor="#FF9639" />
          <stop offset="0.5" stopColor="#EF852E" />
          <stop offset="1" stopColor="#BE3D00" />
        </linearGradient>
        <clipPath id={`${uid}-c0`}>
          <path d={CIRCLE_PATH} fill="white" />
        </clipPath>
        <clipPath id={`${uid}-c1`}>
          <rect width="24" height="24" fill="white" transform="translate(4 4)" />
        </clipPath>
      </defs>
    </svg>
  );
}

"use client";

/**
 * BadgeStatus — Generado por Concorde
 * Fuente: https://voyager-ds.vercel.app/preview/components/pase1
 * Generado: 2026-05-28
 *
 * Pill badge de estado de subasta: EN VIVO (animated dot) · PRÓXIMA (blinking clock)
 */

import type { JSX } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

export type BadgeStatusVariant = "live" | "proxima";

export interface BadgeStatusProps {
  variant: BadgeStatusVariant;
  /** Override de label / contenido editable (default: "EN VIVO" / "PRÓXIMA") */
  label?: string;
  /** Muestra el dot (live) / reloj (proxima). false = solo el texto. Default true. */
  icon?: boolean;
  className?: string;
}

// ─── Self-contained CSS ───────────────────────────────────────────────────────

const STYLE_ID = "concorde-badgestatus-styles";

const BADGESTATUS_STYLES = `
/* Pulso del punto EN VIVO — frames exactos del SVG: On (6px, opacidad 1) ↔ On-1 (4px, 0.28) */
@keyframes badgestatus-live-pulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50%      { opacity: 0.28; transform: scale(0.67); }
}

/* Parpadeo del reloj PRÓXIMA — On (sólido) ↔ Off (0.28) */
@keyframes badgestatus-clock-blink {
  0%, 100% { opacity: 1; transform: scale(1); }
  50%      { opacity: 0.28; transform: scale(0.85); }
}

/* ── Base pill ── */
.badgestatus {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 3px 8px 3px 6px;
  border-radius: 9999px;
  font-family: var(--vmc-font-display, 'Plus Jakarta Sans', system-ui, sans-serif);
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 0.07em;
  text-transform: uppercase;
  white-space: nowrap;
  backdrop-filter: blur(6px);
  -webkit-backdrop-filter: blur(6px);
  color: oklch(1 0 0);
  border: 1px solid transparent;
  user-select: none;
}

/* ── EN VIVO — sync EXACTO SVG (1310:11895 / 11904) ──
   bg naranja diagonal + borde gradiente cálido + ring naranja */
.badgestatus--live {
  background-image:
    linear-gradient(135deg, #ff9639 0%, #ef852e 40%, #be3d00 100%),
    linear-gradient(135deg, #ffbc83 0%, rgba(255,255,255,0.45) 40%, #da6c1e 75%, #ffbc83 100%);
  background-origin: padding-box, border-box;
  background-clip: padding-box, border-box;
  box-shadow:
    rgba(239, 133, 46, 0.45) 0px 2px 10px,
    rgba(255, 255, 255, 0.14) 0px 1px 0px inset;
}

/* ── PRÓXIMA — sync EXACTO SVG (1310:11797 / 11799) ──
   bg morado diagonal + borde gradiente lila + glow morado #200068 */
.badgestatus--proxima {
  background-image:
    linear-gradient(135deg, #8460e5 0%, #3b1782 100%),
    linear-gradient(135deg, #8776ff 0%, rgba(255,255,255,0.4) 38%, #532bc7 68%, #8776ff 100%);
  background-origin: padding-box, border-box;
  background-clip: padding-box, border-box;
  box-shadow:
    rgba(32, 0, 104, 0.5) 0px 2px 10px,
    rgba(255, 255, 255, 0.1) 0px 1px 0px inset;
}

/* ── Pulsing dot (live) ── */
.badgestatus-dot {
  width: 6px;
  height: 6px;
  border-radius: 9999px;
  background: #ffffff;
  flex-shrink: 0;
  animation: badgestatus-live-pulse 1.4s ease-in-out infinite;
  position: relative;
}

/* ── Blinking clock (proxima) ── */
.badgestatus-clock {
  flex-shrink: 0;
  display: inline-flex;
  align-items: center;
  animation: badgestatus-clock-blink 1.4s ease-in-out infinite;
}

/* ── Reduced motion ── */
@media (prefers-reduced-motion: reduce) {
  .badgestatus-dot   { animation: none; }
  .badgestatus-clock { animation: none; }
}
`;

let _stylesInjected = false;

// ─── Clock SVG (Próxima) ──────────────────────────────────────────────────────

function ClockIcon(): JSX.Element {
  return (
    <svg
      width="10"
      height="10"
      viewBox="0 0 24 24"
      fill="none"
      stroke="rgba(255,255,255,0.92)"
      strokeWidth="2.2"
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
    >
      <circle cx="12" cy="12" r="10" />
      <polyline points="12 6 12 12 16 14" />
    </svg>
  );
}

// ─── Component ────────────────────────────────────────────────────────────────

const LABEL_DEFAULTS: Record<BadgeStatusVariant, string> = {
  live:    "EN VIVO",
  proxima: "PRÓXIMA",
};

export default function BadgeStatus({
  variant,
  label,
  icon = true,
  className = "",
}: BadgeStatusProps): JSX.Element {
  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = BADGESTATUS_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  const displayLabel = label ?? LABEL_DEFAULTS[variant];

  const classes = [
    "badgestatus",
    `badgestatus--${variant}`,
    className,
  ].filter(Boolean).join(" ");

  return (
    <>
      <style
        id={`${STYLE_ID}-ssr`}
        suppressHydrationWarning
        dangerouslySetInnerHTML={{ __html: BADGESTATUS_STYLES }}
      />
      <span
        className={classes}
        role="status"
        aria-label={displayLabel}
      >
        {icon && variant === "live" ? (
          <span className="badgestatus-dot" aria-hidden="true" />
        ) : null}
        {icon && variant === "proxima" ? (
          <span className="badgestatus-clock" aria-hidden="true">
            <ClockIcon />
          </span>
        ) : null}
        <span>{displayLabel}</span>
      </span>
    </>
  );
}

/**
 * Signal — Generado por Concorde
 * Fuente: Figma VOYAGER · "hdr-signal1" (3143:13306)
 *
 * Indicador de señal: 5 barras crecientes (rx1). Las activas con gradiente
 * naranja (#FF9639 → #EF852E → #BE3D00), las inactivas en blanco 20%.
 * `level` (0-5) controla cuántas están activas (default 4). Copia exacta de los
 * paths del SVG. useId para id único.
 */

import { useId } from "react";
import type { JSX } from "react";

export interface SignalProps {
  /** Barras activas (0-5) — default 4 */
  level?: number;
  /** Ancho en px (alto = width × 16/28) — default 28 */
  width?: number;
  /** Texto accesible. Si se omite, es decorativo (aria-hidden). */
  title?: string;
  className?: string;
}

const BARS = [
  "M3 12H1C0.447715 12 0 12.4477 0 13V15C0 15.5523 0.447715 16 1 16H3C3.55228 16 4 15.5523 4 15V13C4 12.4477 3.55228 12 3 12Z",
  "M9 9H7C6.44772 9 6 9.44772 6 10V15C6 15.5523 6.44772 16 7 16H9C9.55228 16 10 15.5523 10 15V10C10 9.44772 9.55228 9 9 9Z",
  "M15 6H13C12.4477 6 12 6.44772 12 7V15C12 15.5523 12.4477 16 13 16H15C15.5523 16 16 15.5523 16 15V7C16 6.44772 15.5523 6 15 6Z",
  "M21 3H19C18.4477 3 18 3.44772 18 4V15C18 15.5523 18.4477 16 19 16H21C21.5523 16 22 15.5523 22 15V4C22 3.44772 21.5523 3 21 3Z",
  "M27 0H25C24.4477 0 24 0.447715 24 1V15C24 15.5523 24.4477 16 25 16H27C27.5523 16 28 15.5523 28 15V1C28 0.447715 27.5523 0 27 0Z",
];

export default function Signal({ level = 4, width = 28, title, className = "" }: SignalProps): JSX.Element {
  const uid = useId().replace(/:/g, "-");
  const gid = `signal-grad-${uid}`;
  const height = (width * 16) / 28;

  return (
    <svg
      width={width}
      height={height}
      viewBox="0 0 28 16"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      role={title ? "img" : undefined}
      aria-hidden={title ? undefined : true}
    >
      {title ? <title>{title}</title> : null}
      {BARS.map(function renderBar(d, i) {
        const active = i < level;
        return <path key={i} d={d} fill={active ? `url(#${gid})` : "rgba(255,255,255,0.2)"} />;
      })}
      <defs>
        <linearGradient id={gid} x1="0" y1="0" x2="0" y2="1">
          <stop stopColor="#FF9639" />
          <stop offset="0.4" stopColor="#EF852E" />
          <stop offset="1" stopColor="#BE3D00" />
        </linearGradient>
      </defs>
    </svg>
  );
}

"use client";

/**
 * SalaStatus — Generado por Concorde
 * Fuente: Figma VOYAGER · "Sala status" (443×90)
 *
 * Barra de cabecera de sala (443×90): gradiente naranja→morado, borde gradiente
 * y sombra. Izquierda: vehículo + año + placa. Derecha: label + TimerIcon +
 * countdown (mono). Usa el componente TimerIcon. Editable por props.
 */

import type { JSX } from "react";
import TimerIcon from "../TimerIcon/TimerIcon";

export interface SalaStatusProps {
  /** Nombre del vehículo (default "Toyota Etios") */
  title?: string;
  /** Año (default "2021") */
  year?: string;
  /** Etiqueta de placa (default "Placa") */
  placaLabel?: string;
  /** Placa (default "P3U448") */
  placa?: string;
  /** Etiqueta del timer (default "INICIÓ HACE") */
  timerLabel?: string;
  /** Tiempo / countdown (default "00:00:10") */
  time?: string;
  className?: string;
}

const STYLE_ID = "concorde-salastatus-styles";

const SALASTATUS_STYLES = `
.psala {
  position: relative;
  box-sizing: border-box;
  width: 443px;
  max-width: 100%;
  height: 90px;
  background: linear-gradient(120deg, #FF9639 0%, #EF852E 40%, #8460E5 100%);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 0 20px;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
  overflow: hidden;
}
/* Sheen superior */
.psala::before {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(180deg, rgba(255,255,255,0.12) 0%, rgba(255,255,255,0) 45%);
  pointer-events: none;
}
.psala__left { position: relative; z-index: 1; display: flex; flex-direction: column; gap: 4px; min-width: 0; }
.psala__title { font-size: 20px; font-weight: 800; line-height: 1.1; color: #ffffff; white-space: nowrap; }
.psala__title-year { font-weight: 600; color: rgba(255,255,255,0.72); margin-left: 6px; }
.psala__placa { font-size: 14px; font-weight: 500; color: rgba(255,255,255,0.85); white-space: nowrap; }
.psala__placa-val { font-weight: 700; color: #ffffff; margin-left: 6px; }
.psala__right { position: relative; z-index: 1; display: flex; flex-direction: column; align-items: flex-end; gap: 3px; flex-shrink: 0; }
.psala__timer-label {
  display: inline-flex; align-items: center; gap: 6px;
  font-size: 10px; font-weight: 700; letter-spacing: 0.06em; text-transform: uppercase;
  color: rgba(255,255,255,0.85);
}
.psala__time {
  font-family: var(--vmc-font-mono, "Roboto Mono", ui-monospace, monospace);
  font-size: 22px; font-weight: 700; line-height: 1; color: #ffffff;
  font-variant-numeric: tabular-nums; letter-spacing: 0.02em;
}
`;

let _stylesInjected = false;

export default function SalaStatus({
  title = "Toyota Etios",
  year = "2021",
  placaLabel = "Placa",
  placa = "P3U448",
  timerLabel = "INICIÓ HACE",
  time = "00:00:10",
  className = "",
}: SalaStatusProps): JSX.Element {
  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = SALASTATUS_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: SALASTATUS_STYLES }} />
      <div className={`psala ${className}`.trim()}>
        <div className="psala__left">
          <span className="psala__title">
            {title}
            {year ? <span className="psala__title-year">{year}</span> : null}
          </span>
          <span className="psala__placa">
            {placaLabel}
            {placa ? <span className="psala__placa-val">{placa}</span> : null}
          </span>
        </div>
        <div className="psala__right">
          <span className="psala__timer-label">
            <TimerIcon size={16} color="rgba(255,255,255,0.85)" />
            {timerLabel}
          </span>
          <span className="psala__time">{time}</span>
        </div>
      </div>
    </>
  );
}

/**
 * TimerIcon — Generado por Concorde
 * Fuente: Figma VOYAGER · "timericon" (3201)
 *
 * Icono de temporizador/reloj (22×22), trazo redondeado 1.83. Copia exacta del
 * path del SVG. Tamaño y color personalizables (default currentColor).
 */

import type { JSX } from "react";

export interface TimerIconProps {
  /** Tamaño en px (default 22) */
  size?: number;
  /** Color del trazo (default "currentColor") */
  color?: string;
  /** Texto accesible. Si se omite, es decorativo (aria-hidden). */
  title?: string;
